The Composite pattern organizes objects into tree structures, making them work together like one. It lets clients treat individual objects and compositions of objects in a similar way.
This is useful when dealing with things organized in a tree-like structure, such as files and folders in a computer&rsquo;s file system.
Key Participants: Component: This is the base interface or abstract class that declares the common operations for both leaf objects and composite objects. It defines methods for accessing, manipulating, and iterating through child components. Leaf: Leaf objects are the individual objects that don&rsquo;t have any child components. They implement the operations defined in the Component interface. Composite: Composite objects are containers that can hold child components. They implement the operations defined in the Component interface but also manage a collection of child components. +------------------+ | Component | +------------------+ / \ / \ +-------+ +-----------+ | Leaf | | Composite | +-------+ +-----------+ classDiagramclass Component {+operation()+add(Component c)+remove(Component c)+getChild(int index)}class Leaf {+operation()}class Composite {+operation()+add(Component c)+remove(Component c)+getChild(int index)}Component <|-- LeafComponent <|-- CompositeExamples Files and Folders classDiagramclass FileSystemComponent {+getName()+displayInfo()}class File {+getName()+displayInfo()}class Folder {+addComponent(FileSystemComponent component)+removeComponent(FileSystemComponent component)+displayInfo()}FileSystemComponent <|-- FileFileSystemComponent <|-- Folderjava python go import java.util.ArrayList; import java.util.List; // Component interface interface FileSystemComponent { String getName(); void displayInfo(); } // Leaf class class File implements FileSystemComponent { private String name; public File(String name) { this.name = name; } public String getName() { return name; } public void displayInfo() { System.out.println(&#34;File: &#34; + name); } } // Composite class class Folder implements FileSystemComponent { private String name; private List&lt;FileSystemComponent&gt; contents = new ArrayList&lt;&gt;(); public Folder(String name) { this.name = name; } public String getName() { return name; } public void addComponent(FileSystemComponent component) { contents.add(component); } public void removeComponent(FileSystemComponent component) { contents.remove(component); } public void displayInfo() { System.out.println(&#34;Folder: &#34; + name); System.out.println(&#34;Contents:&#34;); for (FileSystemComponent component : contents) { component.displayInfo(); } } } public class Main { public static void main(String[] args) { FileSystemComponent file1 = new File(&#34;document.txt&#34;); FileSystemComponent file2 = new File(&#34;image.jpg&#34;); FileSystemComponent file3 = new File(&#34;presentation.ppt&#34;); FileSystemComponent folder1 = new Folder(&#34;Documents&#34;); folder1.addComponent(file1); folder1.addComponent(file3); FileSystemComponent folder2 = new Folder(&#34;Pictures&#34;); folder2.addComponent(file2); FileSystemComponent rootFolder = new Folder(&#34;Root&#34;); rootFolder.addComponent(folder1); rootFolder.addComponent(folder2); rootFolder.displayInfo(); } } Employees and Departments classDiagramclass Employee {+getName()+getRole()+displayInformation()}class IndividualEmployee {+getName()+getRole()+displayInformation()}class Department {+addEmployee(Employee employee)+removeEmployee(Employee employee)+displayInformation()}Employee <|-- IndividualEmployeeEmployee <|-- Departmentjava python go import java.util.ArrayList; import java.util.List; // Component interface interface Employee { String getName(); String getRole(); void displayInformation(); } // Leaf class class IndividualEmployee implements Employee { private String name; private String role; public IndividualEmployee(String name, String role) { this.name = name; this.role = role; } public String getName() { return name; } public String getRole() { return role; } public void displayInformation() { System.out.println(&#34;Name: &#34; + name + &#34;, Role: &#34; + role); } } // Composite class class Department implements Employee { private String name; private String description; private List&lt;Employee&gt; employees = new ArrayList&lt;&gt;(); public Department(String name, String description) { this.name = name; this.description = description; } public String getName() { return name; } public String getRole() { return &#34;Department&#34;; } public void addEmployee(Employee employee) { employees.add(employee); } public void removeEmployee(Employee employee) { employees.remove(employee); } public void displayInformation() { System.out.println(&#34;Department: &#34; + name + &#34; (&#34; + description + &#34;)&#34;); System.out.println(&#34;Employees:&#34;); for (Employee employee : employees) { employee.displayInformation(); } } } public class Main { public static void main(String[] args) { Employee john = new IndividualEmployee(&#34;John Smith&#34;, &#34;Software Engineer&#34;); Employee mary = new IndividualEmployee(&#34;Mary Johnson&#34;, &#34;Project Manager&#34;); Department engineering = new Department(&#34;Engineering&#34;, &#34;Develops software products&#34;); engineering.addEmployee(john); Department management = new Department(&#34;Management&#34;, &#34;Oversees projects&#34;); management.addEmployee(mary); Department company = new Department(&#34;Company&#34;, &#34;Global technology firm&#34;); company.addEmployee(engineering); company.addEmployee(management); company.displayInformation(); } } Menu Item and Menu Category classDiagramclass MenuItem {+getName()+getPrice()+display()}class Dish {+getName()+getPrice()+display()}class MenuCategory {+addItem(MenuItem item)+removeItem(MenuItem item)+display()}MenuItem <|-- DishMenuItem <|-- MenuCategoryjava python go import java.util.ArrayList; import java.util.List; // Component interface interface Employee { String getName(); String getRole(); void displayInformation(); } // Leaf class class IndividualEmployee implements Employee { private String name; private String role; public IndividualEmployee(String name, String role) { this.name = name; this.role = role; } public String getName() 